    {2645,"Molten Seed",236301,2,0,0,{"wago"},"Ragnaros creates Molten Seed at the location of 10 random players from the nearby lava, inflicting $98498s1 Fire damage to all players within $98498A1 yards of a seed. After $98520d the Molten Seed bursts into a Molten Inferno.$[4,6\n\n\n\nIn 25 player raids, Ragnaros targets 20 players.$]",-1,2646,0,0,198,3536,20,2640,0},
    {2646,"Molten Inferno",525024,2,0,0,{"wago"},"When Molten Seeds burst they create a Molten Inferno, inflicting $98518s1 Fire damage to all players and creating a Molten Elemental. The damage inflicted decreases the farther away the player stands from the seed.",-1,0,0,0,198,2647,21,2645,0},
    {2647,"Molten Elemental",0,1,0,0,{"wago"},"A Molten Inferno creates a Molten Elemental, which attacks and fixates on a random player.",-1,2648,38520,0,198,0,22,2645,0},
    {2648,"Molten Power",132221,2,0,2,{"wago"},"Molten Elementals within $100158A1 yards empower other Molten Elementals, increasing their damage dealt by $100158s1% and granting immunity to snare and stun effects.",12,0,0,8,198,0,23,2647,0},
