    {2651,"Burning Speed",135788,2,0,0,{"wago"},"For every 5% of their remaining health above 50%, Sons of Flame move $99414s2% faster. When players reduce a Son of Flame to below 50% remaining health, the Son of Flame loses the Burning Speed effect.",-1,0,0,0,198,2652,28,2650,0},
    {2652,"Supernova",525026,2,0,0,{"wago"},"When a Son of Flame reaches Sulfuras it explodes in a Supernova, inflicting $99112s1 Fire damage to all players.",-1,0,0,0,198,0,29,2650,0},
