    {2798,"Pool of Acrid Tears",132108,2,0,2,{"wago"},"High Priest Venoxis summons a venomous puddle near the player farthest from him. The puddle grows over time and inflicts $96521s1 Nature damage every $96520t1 seconds to players that stand in it.",-2,0,0,32,175,2799,10,2791,0},
    {2799,"Breath of Hethiss",132103,2,0,2,{"wago"},"High Priest Venoxis spews forth a stream of acrid venom that inflicts $96744s1 Nature damage to enemies in a $96744a1-yard cone in front of him every $96509t1 seconds for $96509d.",-2,0,0,0,175,0,11,2791,0},
    {2800,"Venomous Effusion",132108,2,0,2,{"wago"},"During the encounter a maze of poison clouds appears on the ground. The poison inflicts $96685s1 Nature damage to enemies that step into the clouds.",-2,0,0,0,175,2802,2,2787,0},
