    {2802,"Word of Hethiss",252271,2,0,2,{"wago"},"At the start of the battle, High Priest Venoxis calls upon the Word of Hethis. This inflicts $96560s1 Nature damage to players within $96560A1 yards and knocks them back.",-2,0,0,0,175,2795,3,2787,0},
    {2803,"Toxic Explosion",132104,2,0,2,{"wago"},"When Toxic Link breaks, it causes a Toxic Explosion at the location of each linked player. Toxic Explosion inflicts $96489s1 Nature damage to players within $96489A1 yards.",-2,0,0,0,175,0,6,2796,0},
