    {2845,"Herald of the Burning End",0,1,0,2,{"wago"},"During Stage 1, a Herald of the Burning End periodically appears and begins casting Cataclysm. The Herald is immune to all damage, but dies when he casts Cataclysm.",12,2846,38652,8,194,0,26,2820,0},
