    {3120,"Inferno Rush",135926,2,0,0,{"wago"},"Ignacious leaps to a distant target, knocking away all enemies within $82857A1 yards of the point of impact and inflicting $82857s1 Fire damage. Ignacious then rushes back to his last target, leaving a trail of fire in his wake. Standing within this fire inflicts $82860s1 Fire damage every $88579t1 sec.",-1,0,0,0,158,3121,13,3118,0},
    {3121,"Flame Torrent",236216,2,0,0,{"wago"},"Ignacious unleashes plumes of fire from his hands, inflicting $88558s1 Fire damage every $82777t1 sec for $82777d in a $88558a1 yard 30 degree cone in front of him.",-1,0,0,1,158,3122,14,3118,0},
    {3122,"Burning Blood",132847,2,0,0,{"wago"},"Ignacious boils the blood of a random player, inflicting increasing Fire damage every $82660t1 sec, but also causing nearby players within $82662A1 yards to become Flame Imbued.",-1,3151,0,0,158,0,15,3118,0},
