    {4126,"Cauterize",236216,2,0,0,{"wago"},"Alexstrasza Cauterizes the Blistering Tentacles, inflicting lethal damage over $105565d. Cauterize also reduces the damage inflicted by Corrupted Blood.$[5,6\n\n\n\nIn Heroic Difficulty Alexstrasza Cauterizes the Corrupting Parasite, inflicting $109045s1% Fire damage every $108840t1 sec.$]",-1,0,0,0,333,0,32,4124,0},
    {4127,"Nozdormu",0,1,0,0,{"wago"},nil,-1,4128,39323,0,333,4130,33,4123,0},
