    {7065,"Sandstorm",796638,2,0,0,{"wago"},"Sul the Sandcrawler uses this ability while possessed by the spirit of Gara'jal.\n\n\n\nSul the Sandcrawler summons a sandstorm that inflicts $136899s1 Nature damage to all players every second for $136894d, and animates all existing pools of Quicksand, transforming them into Living Sand.",-1,7066,0,0,816,7068,20,7049,0},
    {7066,"Living Sand",0,1,0,1,{"wago"},"Living Sand creatures rise from pools of Quicksand whenever a Sandstorm occurs, and remain active until they are killed.\n\n\n\nWhen a Living Sand dies, it creates a new pool of Quicksand at their location.",-1,7067,47252,0,816,0,21,7065,0},
