    {7893,"Noxious Poison",236271,2,0,0,{"wago"},"He Softfoot coats his weapon in a Noxious Poison, causing successful melee attacks to create pools of poison on the ground, inflicting $144367s1 Nature damage every second. These pools may be jumped over.\n\n\n\nThis effect is removed when He Softfoot begins his Desperate Measures.",-1,0,0,0,849,7894,26,7892,0},
    {7894,"Instant Poison",132106,2,0,0,{"wago"},"He Softfoot coats his weapon in an Instant Poison, causing successful melee attacks to inflict $143224s1 additional Nature damage.",-1,0,0,0,849,0,27,7892,0},
    {7895,"Breath of Y'Shaarj",136194,2,0,0,{"wago"},"Malkorok channels the power of Y'Shaarj, causing the areas recently hit by Arcing Smash to explode, inflicting $142816s1 Shadow damage.",-1,0,0,0,846,7897,13,7896,0},
