    {8358,"Set'thik Wind Wielder",0,1,0,0,{"wago"},nil,-1,8376,48846,0,870,0,33,8439,0},
    {8359,"Lightweight Crate of Goods",0,0,0,0,{"wago"},"These small crates of goods carry front-line enemy forces. A small amount of Titan Energy fuels their creation and can be defeated with fewer players.",-1,8434,0,0,870,8366,36,0,0},
    {8360,"Animated Stone Mogu",0,1,0,0,{"wago"},nil,-1,8379,48814,0,870,8361,38,8434,0},
