    {8406,"Earthen Shard",132838,2,0,0,{"wago"},"Summons a shard of earthen material, striking a target for $144923s1 Nature damage.",-1,0,0,64,870,0,40,8360,0},
    {8407,"Throw Explosives",135863,2,0,0,{"wago"},"Tosses specialized bombs that immediately explode for $145706s1 Physical damage to targets within $145706A1 yards.",-1,0,0,0,870,0,48,8363,0},
    {8408,"Overcharge",839983,2,0,2,{"wago"},"When activated weapons arrive on the assembly line, Siegecrafter Blackfuse will Overcharge one of them, increasing its power and effectiveness.",12,0,0,8,865,8476,7,8194,0},
    {8409,"Overcharged Missile Turret",839983,2,0,2,{"wago"},"When Overcharged, the Shockwave Missile Turret will fire Shockwave Missiles which persist and continuously barrage the platform with drills and seismic energy until destroyed by players.",12,0,0,8,865,0,19,8204,0},
    {8410,"Overcharged Laser Turret",839983,2,0,2,{"wago"},"When Overcharged, Siegecrafter Blackfuse's laser turrets will fire a split beam, creating three concentric arcs of Superheated ground.",12,0,0,8,865,0,22,8208,0},
    {8411,"Overcharged Electromagnet",839983,2,0,2,{"wago"},"When Overcharged, the Electromagnet will periodically reverse polarities, pushing both players and sawblades in and out from the magnet.",12,0,0,8,865,0,25,8210,0},
    {8412,"Overcharged Crawler Mines",839983,2,0,2,{"wago"},"When Overcharged, Crawler Mines activate a construction matrix within their machinery. This construction matrix enables them to create two new Crawler Mines when they are destroyed.",12,0,0,0,865,0,30,8212,0},
    {8413,"Frayed",897135,2,0,0,{"wago"},"When the Amalgam reaches 50% health remaining, and for every 10% health lost thereafter, the Amalgam spawns an Unleashed Manifestation of Corruption.",-1,0,0,32,866,8483,11,8216,0},
    {8414,"Residual Burn",429590,2,0,3,{"wago"},"Secondary targets are afflicted with Residual Burn, taking $144007s1% increased damage from Inferno Strike for $144007d.",0,0,0,8,849,0,9,7959,0},
